import React, { useState, useEffect } from 'react';
import { MenuBurgerSvg } from "./asset/Svg/Svg";
import Links from "./asset/links/Links";
import Social from "./asset/social/Social";
import SwitchTheme from "./asset/SwitchTheme/SwitchTheme";
import "./test.css";

export function MenuBurger() {
    const [isOpen, setIsOpen] = useState(false);

    const toggleMenu = () => {
        setIsOpen(!isOpen);
    };

    // Fermer le menu si on clique en dehors
    useEffect(() => {
        const handleClickOutside = (event) => {
            const menu = document.querySelector('.burger-menu');
            const button = document.querySelector('.burger-icon');

            if (isOpen && menu && !menu.contains(event.target) && !button.contains(event.target)) {
                setIsOpen(false);
            }
        };

        document.addEventListener('mousedown', handleClickOutside);
        return () => {
            document.removeEventListener('mousedown', handleClickOutside);
        };
    }, [isOpen]);

    return (
        <div className="burger-container">
            <button className="burger-icon" onClick={toggleMenu}>
                <MenuBurgerSvg/>
            </button>

            <div className={`burger-menu ${isOpen ? 'open' : ''}`}>
                <div className="menu-items">
                    <Links />
                    <Social />
                    <SwitchTheme />
                </div>
            </div>
        </div>
    );
}
